struct ObserverCollectionSummary {
    std::size_t totalObservers;
    bool containsDirectObserver;
    bool containsTransitiveObserver;
};

ObserverCollectionSummary test_observer_collection() {
    // 1. Create two NamedObserverNode instances with unique names
    NamedObserverNode directNode("direct_observer");
    NamedObserverNode transitiveNode("transitive_observer");

    // 2. Get the singleton ObserverGraph instance
    auto& observerGraph = reaction::ObserverGraph::getInstance();

    // 3. Register both nodes using ObserverGraph::addNode()
    observerGraph.addNode(directNode.getPtr());
    observerGraph.addNode(transitiveNode.getPtr());

    // 4. Set up direct observer relationship using ObserverGraph::addObserver()
    observerGraph.addObserver(directNode, transitiveNode);

    // 5. Set up transitive observer relationship by adding the transitive node as an observer of the direct node
    observerGraph.addObserver(transitiveNode, directNode);

    // 6. Create a NodeSet to store collected observers
    reaction::NodeSet collectedObservers;

    // 7. Use ObserverGraph::collectObservers() to collect observers starting from the direct node
    observerGraph.collectObservers(directNode.getPtr(), collectedObservers);

    // 8. Check if the direct observer is in the collected set
    bool hasDirect = !collectedObservers.count(directNode.getPtr()).empty();

    // 9. Check if the transitive observer is in the collected set
    bool hasTransitive = !collectedObservers.count(transitiveNode.getPtr()).empty();

    // 10. Return an ObserverCollectionSummary with the total number of observers and the boolean checks
    return ObserverCollectionSummary{
        collectedObservers.size(),
        hasDirect,
